ALTER TABLE media_files ADD COLUMN IF NOT EXISTS metadata_json JSONB NOT NULL DEFAULT '{}'::jsonb;
UPDATE media_files SET metadata_json = '{}'::jsonb WHERE metadata_json IS NULL;
ALTER TABLE media_files ALTER COLUMN metadata_json SET DEFAULT '{}'::jsonb;
ALTER TABLE media_files ALTER COLUMN metadata_json SET NOT NULL;
UPDATE media_files SET metadata_json = metadata_json || jsonb_strip_nulls(jsonb_build_object('size_bytes', to_jsonb(size_bytes), 'width_bytes', CASE WHEN metadata_json ? 'width_bytes' THEN metadata_json->'width_bytes' WHEN metadata_json ? 'width' THEN metadata_json->'width' ELSE NULL END, 'height_bytes', CASE WHEN metadata_json ? 'height_bytes' THEN metadata_json->'height_bytes' WHEN metadata_json ? 'height' THEN metadata_json->'height' ELSE NULL END, 'mime_type', to_jsonb(mime_type), 'extension', CASE WHEN metadata_json ? 'extension' THEN metadata_json->'extension' ELSE NULL END, 'duration_seconds', CASE WHEN metadata_json ? 'duration_seconds' THEN metadata_json->'duration_seconds' WHEN metadata_json ? 'duration' THEN metadata_json->'duration' WHEN metadata_json ? 'length' THEN metadata_json->'length' WHEN duration > 0 THEN to_jsonb(duration) ELSE NULL END, 'bitrate', CASE WHEN metadata_json ? 'bitrate' THEN metadata_json->'bitrate' ELSE NULL END, 'fps', CASE WHEN metadata_json ? 'fps' THEN metadata_json->'fps' WHEN metadata_json ? 'framerate' THEN metadata_json->'framerate' ELSE NULL END, 'video_codec', CASE WHEN metadata_json ? 'video_codec' THEN metadata_json->'video_codec' WHEN metadata_json ? 'output_codecs' THEN metadata_json->'output_codecs' ELSE NULL END, 'audio_codec', CASE WHEN metadata_json ? 'audio_codec' THEN metadata_json->'audio_codec' ELSE NULL END, 'has_audio', CASE WHEN metadata_json ? 'has_audio' THEN metadata_json->'has_audio' ELSE NULL END, 'is_hdr', CASE WHEN metadata_json ? 'is_hdr' THEN metadata_json->'is_hdr' ELSE NULL END, 'page_count', CASE WHEN metadata_json ? 'page_count' THEN metadata_json->'page_count' ELSE NULL END, 'has_password', CASE WHEN metadata_json ? 'has_password' THEN metadata_json->'has_password' ELSE NULL END, 'archive_entries', CASE WHEN metadata_json ? 'archive_entries' THEN metadata_json->'archive_entries' ELSE NULL END));
CREATE INDEX IF NOT EXISTS idx_media_files_metadata_json_gin ON media_files USING GIN (metadata_json);
